import { defineComponentSlotStyle, focusRingStyle } from "@yamada-ui/react"

export const ratingStyle = defineComponentSlotStyle({
  base: {
    group: { position: "relative" },
    icon: {
      alignItems: "center",
      clipPath: "{clip-path}",
      display: "inline-flex",
      fill: "currentColor",
      justifyContent: "center",
    },
    item: {
      "&:has(input:focus-visible)": { ...focusRingStyle.outside },
      color: { base: "{empty-color}", _filled: "{filled-color}" },
      cursor: "pointer",
      display: "block",
      lineHeight: "0",
      rounded: "l1",
      _notLast: { inset: 0, position: "absolute" },
      _readOnly: { layerStyle: "readOnly" },
      _disabled: { layerStyle: "disabled" },
    },
    root: {
      "--empty-color": "colors.bg.muted",
      "--filled-color": "colorScheme.solid",
      display: "flex",
      w: "max-content",
      _container: [
        {
          css: { "--empty-color": "colors.bg" },
          style: '--form-group-variant: "panel"',
        },
        {
          css: { "--empty-color": "colors.bg" },
          style: '--fieldset-root-variant: "panel"',
        },
        {
          css: { "--empty-color": "colors.bg" },
          style: '--form-group-variant: "elevated"',
        },
        {
          css: { "--empty-color": "colors.bg" },
          style: '--fieldset-root-variant: "elevated"',
        },
      ],
    },
  },

  sizes: {
    xs: { icon: { fontSize: "md" } },
    sm: { icon: { fontSize: "lg" } },
    md: { icon: { fontSize: "xl" } },
    lg: { icon: { fontSize: "2xl" } },
    xl: { icon: { fontSize: "3xl" } },
  },

  defaultProps: {
    size: "md",
  },
})

export type RatingStyle = typeof ratingStyle

import { page, render } from "#test/browser"
import { Rating } from "."

const dispatchMouse = (
  el: EventTarget,
  type: "mousedown" | "mouseenter" | "mouseleave" | "mousemove" | "mouseout",
  init: MouseEventInit = {},
) => {
  el.dispatchEvent(new MouseEvent(type, { bubbles: true, ...init }))
}

const dispatchTouchStart = (
  el: EventTarget,
  touches: { clientX: number; clientY: number }[] = [],
) => {
  const event = new Event("touchstart", {
    bubbles: true,
    cancelable: true,
  }) as Event & { touches: { clientX: number; clientY: number }[] }

  Object.defineProperty(event, "touches", { value: touches })

  el.dispatchEvent(event)
}

const getRatingRect = (testId: string) => {
  const rating = page.getByTestId(testId).element()

  if (!(rating instanceof HTMLElement))
    throw new Error("Expected an HTMLElement")

  return { rating, rect: rating.getBoundingClientRect() }
}

describe("<Rating />", () => {
  test("fills items up to the hovered position", async () => {
    const { container } = await render(
      <Rating data-testid="rating" height={20} width={100} />,
    )

    const { rating, rect } = getRatingRect("rating")
    const items = container.querySelectorAll(".ui-rating__item")

    for (let i = 1; i < items.length; i++) {
      expect(items[i]).not.toHaveAttribute("data-filled")
    }

    const itemWidth = rect.width / 5

    dispatchMouse(rating, "mouseenter")
    dispatchMouse(rating, "mousemove", {
      clientX: rect.left + itemWidth * 1.5,
      clientY: rect.top + rect.height / 2,
    })

    await expect.poll(() => items[1]?.hasAttribute("data-filled")).toBe(true)
    await expect.poll(() => items[2]?.hasAttribute("data-filled")).toBe(true)
    await expect.poll(() => items[3]?.hasAttribute("data-filled")).toBe(false)

    dispatchMouse(rating, "mouseleave")
    dispatchMouse(rating, "mouseout", { relatedTarget: document.body })

    await expect.poll(() => items[1]?.hasAttribute("data-filled")).toBe(false)
    await expect.poll(() => items[2]?.hasAttribute("data-filled")).toBe(false)
  })

  test("updates value on the mouseDown event", async () => {
    const onChange = vi.fn()
    const { container } = await render(<Rating onChange={onChange} />)
    const items = container.querySelectorAll(".ui-rating__item")

    dispatchMouse(items[3]!, "mousedown", { button: 0 })

    expect(onChange).toHaveBeenCalledExactlyOnceWith(3)
  })

  test("updates value on item touchStart event", async () => {
    const onChange = vi.fn()
    const { container } = await render(<Rating onChange={onChange} />)
    const items = container.querySelectorAll(".ui-rating__item")

    dispatchTouchStart(items[3]!)

    expect(onChange).toHaveBeenCalledExactlyOnceWith(3)
  })

  test("updates value on root touchStart event", async () => {
    const onChange = vi.fn()

    await render(
      <Rating
        data-testid="rating"
        height={20}
        width={100}
        onChange={onChange}
      />,
    )

    const { rating, rect } = getRatingRect("rating")
    const itemWidth = rect.width / 5

    dispatchTouchStart(rating, [
      {
        clientX: rect.left + itemWidth * 1.5,
        clientY: rect.top + rect.height / 2,
      },
    ])

    expect(onChange).toHaveBeenCalledWith(2)
  })

  test("calls preventDefault on root touchEnd", async () => {
    await render(<Rating data-testid="rating" />)

    const { rating } = getRatingRect("rating")
    const event = new Event("touchend", {
      bubbles: true,
      cancelable: true,
    })
    const preventDefaultSpy = vi.spyOn(event, "preventDefault")

    rating.dispatchEvent(event)

    expect(preventDefaultSpy).toHaveBeenCalledWith()
  })

  test("does not update value when disabled", async () => {
    const { container } = await render(<Rating disabled />)
    const items = container.querySelectorAll(".ui-rating__item")

    dispatchMouse(items[3]!, "mousedown", { button: 0 })

    expect(items[3]?.firstChild).not.toHaveAttribute("data-checked")
  })

  test("resets hovered value on blur when mouse is outside", async () => {
    const { container } = await render(<Rating />)
    const inputs = container.querySelectorAll("input[type='radio']")
    const firstInput = inputs[0]
    if (!(firstInput instanceof HTMLInputElement))
      throw new Error("expected input element")

    firstInput.focus()
    dispatchMouse(container.firstChild!, "mouseleave")
    firstInput.blur()

    const activeInput = container.querySelector("input[data-active='true']")
    expect(activeInput).toBeNull()
  })

  test("updates value via keyboard", async () => {
    const onChange = vi.fn()

    const { container, user } = await render(<Rating onChange={onChange} />)

    const inputs = container.querySelectorAll("input[type='radio']")
    const firstInput = inputs[0]
    if (!(firstInput instanceof HTMLInputElement))
      throw new Error("expected input element")

    await user.tab()
    firstInput.focus()
    await user.keyboard("{ArrowRight}")

    await expect.poll(() => document.activeElement === inputs[1]).toBe(true)

    await user.keyboard("{Space}")

    expect(onChange).toHaveBeenCalledWith(1)
  })
})

"use client"

import type { CSSProps, HTMLStyledProps, ThemeProps, FunctionOrValue, Merge, ReactNodeOrFunction } from "@yamada-ui/react"
import type { RatingStyle } from "./rating.style"
import type { UseRatingItemProps, UseRatingProps } from "./use-rating"
import { useMemo } from "react"
import { createSlotComponent, mergeProps, styled, varAttr, runIfFn } from "@yamada-ui/react"
import { StarIcon } from "../icon"
import { ratingStyle } from "./rating.style"
import {
  RatingContext,
  useRating,
  useRatingContext,
  useRatingItem,
} from "./use-rating"

interface ComponentContext extends Pick<
  RatingProps,
  | "color"
  | "emptyIcon"
  | "filledIcon"
  | "groupProps"
  | "iconProps"
  | "inputProps"
  | "itemProps"
> {}

export interface RatingProps
  extends
    Merge<Omit<HTMLStyledProps, "children" | "color">, UseRatingProps>,
    ThemeProps<RatingStyle> {
  /**
   * The color of the filled icons.
   */
  color?: FunctionOrValue<number, CSSProps["color"]>
  /**
   * The empty icon for the rating.
   */
  emptyIcon?: ReactNodeOrFunction<number>
  /**
   * The filled icon for the rating.
   */
  filledIcon?: ReactNodeOrFunction<number>
  /**
   * Props for the rating group.
   */
  groupProps?: FunctionOrValue<number, RatingGroupProps>
  /**
   * Props for the rating item.
   */
  iconProps?: FunctionOrValue<number, RatingIconProps>
  /**
   * Props for the input element.
   */
  inputProps?: FunctionOrValue<number, HTMLStyledProps<"input">>
  /**
   * Props for the rating item.
   */
  itemProps?: FunctionOrValue<number, RatingItemProps>
}

const {
  ComponentContext,
  PropsContext: RatingPropsContext,
  useComponentContext,
  usePropsContext: useRatingPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<RatingProps, RatingStyle, ComponentContext>(
  "rating",
  ratingStyle,
)

export { RatingPropsContext, useRatingPropsContext }

/**
 * `Rating` is a component used to allow users to provide ratings.
 *
 * @see https://yamada-ui.com/docs/components/rating
 */
export const Rating = withProvider<"div", RatingProps>(
  ({
    color,
    emptyIcon,
    filledIcon,
    groupProps,
    iconProps,
    inputProps,
    itemProps,
    ...rest
  }) => {
    const {
      id,
      name,
      count,
      decimal,
      disabled,
      displayValue,
      fractions,
      highlightSelectedOnly,
      hoveredValue,
      interactive,
      outsideRef,
      readOnly,
      required,
      roundedValue,
      setHoveredValue,
      setValue,
      value,
      ariaProps,
      dataProps,
      eventProps,
      getRootProps,
    } = useRating(rest)
    const ratingContext = useMemo(
      () => ({
        id,
        name,
        count,
        decimal,
        disabled,
        displayValue,
        fractions,
        highlightSelectedOnly,
        hoveredValue,
        interactive,
        outsideRef,
        readOnly,
        required,
        roundedValue,
        setHoveredValue,
        setValue,
        value,
        ariaProps,
        dataProps,
        eventProps,
      }),
      [
        id,
        name,
        count,
        decimal,
        disabled,
        fractions,
        highlightSelectedOnly,
        hoveredValue,
        interactive,
        displayValue,
        outsideRef,
        readOnly,
        required,
        roundedValue,
        setHoveredValue,
        setValue,
        value,
        ariaProps,
        dataProps,
        eventProps,
      ],
    )
    const componentContext = useMemo(
      () => ({
        color,
        emptyIcon,
        filledIcon,
        groupProps,
        iconProps,
        inputProps,
        itemProps,
      }),
      [
        color,
        emptyIcon,
        filledIcon,
        groupProps,
        iconProps,
        inputProps,
        itemProps,
      ],
    )

    return (
      <RatingContext value={ratingContext}>
        <ComponentContext value={componentContext}>
          <styled.div {...getRootProps()}>
            {Array.from({ length: count }).map((_, index) => (
              <RatingGroup key={index} value={index + 1} />
            ))}
          </styled.div>
        </ComponentContext>
      </RatingContext>
    )
  },
  "root",
)()

interface RatingGroupProps extends HTMLStyledProps {
  value: number
}

const RatingGroup = withContext<"div", RatingGroupProps>(
  ({ value, ...rest }) => {
    const { fractions } = useRatingContext()
    const { groupProps } = useComponentContext()
    const count = useMemo(
      () => (value === 1 ? fractions + 1 : fractions),
      [value, fractions],
    )

    return (
      <styled.div {...mergeProps(rest, runIfFn(groupProps, value))()}>
        {Array.from({ length: count }).map((_, index) => (
          <RatingItem key={index} groupValue={value} index={index} />
        ))}
      </styled.div>
    )
  },
  "group",
)()

interface RatingItemProps
  extends HTMLStyledProps<"label">, UseRatingItemProps {}

const RatingItem = withContext<"label", RatingItemProps>(
  ({ suppressHydrationWarning, ...props }) => {
    const {
      active,
      filled,
      fractionValue,
      groupValue,
      getInputProps,
      getLabelProps,
    } = useRatingItem(props)
    const {
      emptyIcon = <StarIcon fill="currentColor" strokeColor="currentColor" />,
      filledIcon = <StarIcon fill="currentColor" strokeColor="currentColor" />,
      iconProps,
      inputProps,
      itemProps,
    } = useComponentContext()
    const clipPath =
      fractionValue !== 1
        ? `inset(0 ${active ? 100 - fractionValue * 100 : 100}% 0 0)`
        : undefined

    return (
      <styled.label
        {...getLabelProps({
          suppressHydrationWarning,
          ...runIfFn(itemProps, groupValue),
        })}
      >
        <styled.input
          {...getInputProps({
            suppressHydrationWarning,
            ...runIfFn(inputProps, groupValue),
          })}
        />

        <RatingIcon
          {...{ "--clip-path": clipPath }}
          {...runIfFn(iconProps, groupValue)}
        >
          {filled
            ? runIfFn(filledIcon, groupValue)
            : runIfFn(emptyIcon, groupValue)}
        </RatingIcon>
      </styled.label>
    )
  },
  "item",
)(undefined, ({ groupValue, ...rest }) => {
  const { color } = useComponentContext()

  return {
    "--filled-color": varAttr(runIfFn(color, groupValue), "colors"),
    groupValue,
    ...rest,
  }
})

interface RatingIconProps extends HTMLStyledProps {}

const RatingIcon = withContext<"div", RatingIconProps>("div", "icon")()

"use client"

import type { ChangeEvent, KeyboardEvent, MouseEvent, TouchEvent } from "react"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import type { FieldProps } from "../field"
import { useCallback, useId, useMemo, useRef, useState } from "react"
import {
  mergeProps,
  ariaAttr,
  clampNumber,
  createContext,
  dataAttr,
  handlerAll,
  runKeyAction,
  visuallyHiddenAttributes,
} from "@yamada-ui/react"
import { useControllableState } from "../../hooks/use-controllable-state"
import { useFieldProps } from "../field"

const getRoundedValue = (value: number, to: number) => {
  const rounded = Math.round(value / to) * to
  const precision = `${to}`.split(".")[1]?.length || 0

  return Number(rounded.toFixed(precision))
}

export interface RatingContext extends Omit<UseRatingReturn, "getRootProps"> {}

const [RatingContext, useRatingContext] = createContext<RatingContext>({
  name: "RatingContext",
})

export { RatingContext, useRatingContext }

export interface UseRatingProps
  extends FieldProps, Omit<HTMLProps, "color" | "defaultValue" | "onChange"> {
  /**
   * Number of controls that should be rendered.
   *
   * @default 5
   */
  count?: number
  /**
   * The initial value of the rating.
   *
   * @default 0
   */
  defaultValue?: number
  /**
   * Number of fractions each item can be divided into,
   *
   * @default 1
   */
  fractions?: number
  /**
   * If `true`, only the selected icons will be filled.
   *
   * @default false
   */
  highlightSelectedOnly?: boolean
  /**
   * The top-level id string that will be applied to the rating.
   * The index of the rating item will be appended to this top-level id.
   */
  id?: string
  /**
   * The name of the input element.
   */
  name?: string
  /**
   * The value of the rating.
   */
  value?: number
  /**
   * The callback invoked when value state changes.
   */
  onChange?: (value: number) => void
  /**
   * The callback invoked when hovering over the rating.
   */
  onHover?: (value: number) => void
}

export const useRating = (props: UseRatingProps = {}) => {
  const uuid = useId()
  const {
    props: {
      id = uuid,
      name = uuid,
      count: countProp = 5,
      defaultValue = 0,
      disabled,
      fractions: fractionsProp = 1,
      highlightSelectedOnly = false,
      readOnly,
      required,
      value: valueProp,
      onChange: onChangeProp,
      onHover,
      ...rest
    },
    ariaProps,
    dataProps,
    eventProps,
  } = useFieldProps({ ...props, notSupportReadOnly: true })
  const rootRef = useRef<HTMLDivElement>(null)
  const [value, setValue] = useControllableState({
    defaultValue,
    value: valueProp,
    onChange: onChangeProp,
  })
  const [hoveredValue, setHoveredValue] = useState(-1)
  const outsideRef = useRef(true)
  const fractions = Math.floor(fractionsProp)
  const count = Math.floor(countProp)
  const decimal = 1 / fractions
  const roundedValue = useMemo(
    () => getRoundedValue(value, decimal),
    [decimal, value],
  )
  const interactive = !(readOnly || disabled)
  const displayValue = hoveredValue !== -1 ? hoveredValue : roundedValue

  const getHoveredValue = useCallback(
    (x: number) => {
      if (!rootRef.current) return -1

      const { left, width } = rootRef.current.getBoundingClientRect()
      const itemWidth = width / count

      const hoveredValue = (x - left) / itemWidth

      const value = clampNumber(
        getRoundedValue(hoveredValue + decimal / 2, decimal),
        decimal,
        count,
      )

      return value
    },
    [count, decimal],
  )

  const onMouseEnter = useCallback(() => {
    if (interactive) outsideRef.current = false
  }, [interactive])

  const onMouseLeave = useCallback(() => {
    if (!interactive) return

    setHoveredValue(-1)
    outsideRef.current = true

    if (hoveredValue !== -1) onHover?.(-1)
  }, [hoveredValue, onHover, interactive, setHoveredValue])

  const onMouseMove = useCallback(
    (ev: MouseEvent<HTMLDivElement>) => {
      if (disabled || readOnly) return

      const roundedValue = getHoveredValue(ev.clientX)

      setHoveredValue(roundedValue)

      if (roundedValue !== hoveredValue) onHover?.(roundedValue)
    },
    [disabled, getHoveredValue, hoveredValue, readOnly, onHover],
  )

  const onTouchStart = useCallback(
    (ev: TouchEvent<HTMLDivElement>) => {
      ev.preventDefault()

      const el = ev.touches[0]

      if (!el) return

      const value = getHoveredValue(el.clientX)

      setValue(value)
    },
    [getHoveredValue, setValue],
  )

  const onTouchEnd = useCallback((ev: TouchEvent<HTMLDivElement>) => {
    ev.preventDefault()
  }, [])

  const getRootProps: PropGetter = useCallback(
    ({ ref, ...props } = {}) => {
      const merged = mergeProps(
        dataProps,
        eventProps,
        ariaProps,
        {
          id,
          "aria-label": `${value} Stars`,
          "aria-readonly": ariaAttr(readOnly),
          role: "radiogroup",
        },
        rest,
        props,
        { ref },
        { ref: rootRef },
      )()
      return {
        ...merged,
        onMouseEnter: handlerAll(
          props.onMouseEnter,
          rest.onMouseEnter,
          onMouseEnter,
        ),
        onMouseLeave: handlerAll(
          props.onMouseLeave,
          rest.onMouseLeave,
          onMouseLeave,
        ),
        onMouseMove: handlerAll(
          props.onMouseMove,
          rest.onMouseMove,
          onMouseMove,
        ),
        onTouchEnd: handlerAll(props.onTouchEnd, rest.onTouchEnd, onTouchEnd),
        onTouchStart: handlerAll(
          props.onTouchStart,
          rest.onTouchStart,
          onTouchStart,
        ),
      }
    },
    [
      ariaProps,
      dataProps,
      eventProps,
      id,
      onMouseEnter,
      onMouseLeave,
      onMouseMove,
      onTouchEnd,
      onTouchStart,
      readOnly,
      rest,
      value,
    ],
  )

  return {
    id,
    name,
    count,
    decimal,
    disabled,
    displayValue,
    fractions,
    highlightSelectedOnly,
    hoveredValue,
    interactive,
    outsideRef,
    readOnly,
    required,
    roundedValue,
    setHoveredValue,
    setValue,
    value,
    ariaProps,
    dataProps,
    eventProps,
    getRootProps,
  }
}

export type UseRatingReturn = ReturnType<typeof useRating>

export interface UseRatingItemProps extends HTMLProps<"label"> {
  groupValue: number
  index: number
}

export const useRatingItem = ({
  groupValue,
  index,
  ...rest
}: UseRatingItemProps) => {
  const {
    id: rootId,
    name,
    decimal,
    disabled,
    displayValue,
    highlightSelectedOnly,
    interactive,
    outsideRef,
    readOnly,
    required,
    roundedValue,
    setHoveredValue,
    setValue,
    ariaProps,
    dataProps,
    eventProps,
  } = useRatingContext()
  const fractionValue = decimal * (groupValue === 1 ? index : index + 1)
  const value = useMemo(
    () => getRoundedValue(groupValue - 1 + fractionValue, decimal),
    [decimal, fractionValue, groupValue],
  )
  const active = value === displayValue
  const checked = value === roundedValue
  const filled = highlightSelectedOnly
    ? value === displayValue
    : value <= displayValue
  const id = `${rootId}-${groupValue}-${value}`

  const onBlur = useCallback(() => {
    if (outsideRef.current) setHoveredValue(-1)
  }, [outsideRef, setHoveredValue])

  const onInputChange = useCallback(
    (ev: ChangeEvent<HTMLInputElement>) => {
      if (!interactive) return

      const value = parseFloat(ev.target.value)

      setHoveredValue(value)
    },
    [interactive, setHoveredValue],
  )

  const onChange = useCallback(
    (value: number) => {
      if (!interactive) return

      setValue(value)
    },
    [interactive, setValue],
  )

  const onMouseDown = useCallback(() => {
    onChange(value)
  }, [onChange, value])

  const onTouchStart = useCallback(() => {
    onChange(value)
  }, [onChange, value])

  const onKeyDown = useCallback(
    (ev: KeyboardEvent<HTMLInputElement>) => {
      runKeyAction(ev, {
        Space: () => onChange(value),
      })
    },
    [onChange, value],
  )

  const getLabelProps: PropGetter<"label"> = useCallback(
    ({ style, ...props } = {}) =>
      mergeProps(
        dataProps,
        ariaProps,
        {
          htmlFor: id,
          "data-active": dataAttr(active),
          "data-filled": dataAttr(filled),
        },
        rest,
        props,
        { style },
        {
          style: {
            zIndex: fractionValue !== 1 ? (active ? 1 : -1) : undefined,
          },
        },
        { onMouseDown, onTouchStart },
      )(),
    [
      active,
      ariaProps,
      dataProps,
      filled,
      fractionValue,
      id,
      onMouseDown,
      onTouchStart,
      rest,
    ],
  )

  const getInputProps: PropGetter<"input"> = useCallback(
    (props = {}) => ({
      ...dataProps,
      ...eventProps,
      ...ariaProps,
      id,
      type: "radio",
      name,
      style: visuallyHiddenAttributes.style,
      "aria-label": value.toString(),
      "data-active": dataAttr(active),
      "data-checked": dataAttr(checked),
      checked,
      disabled,
      readOnly,
      required,
      value,
      ...props,
      onBlur: handlerAll(onBlur, props.onBlur),
      onChange: handlerAll(props.onChange, onInputChange),
      onKeyDown: handlerAll(props.onKeyDown, onKeyDown),
    }),
    [
      id,
      name,
      value,
      active,
      checked,
      dataProps,
      eventProps,
      ariaProps,
      disabled,
      readOnly,
      required,
      onBlur,
      onInputChange,
      onKeyDown,
    ],
  )

  return {
    active,
    checked,
    filled,
    fractionValue,
    groupValue,
    value,
    getInputProps,
    getLabelProps,
  }
}

export type UseRatingItemReturn = ReturnType<typeof useRatingItem>
